// // This is a 4-bit ring counter that counts down from 7 to 0.
module ring_counter(clk, reset, q);
    input clk, reset;
    output reg [3:0] q;

    always @(posedge clk or posedge reset) begin
        if (reset)
            q <= 4'b0001;
        else
            q <= {q[2:0], q[3]};
    end
endmodule
